// client/src/utils/apiClient.js (or similar file configuring API requests)

// Ensure this base URL is correctly picked up from your .env file
// For Replit deployments, it should point to your Replit project's URL.
const API_BASE_URL = import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000';

export const fetchEmployees = async () => {
  try {
    // The fetch request should use the full absolute URL
    const response = await fetch(`${API_BASE_URL}/api/employees`);

    if (!response.ok) {
      // This block would only be reached if a connection was made but returned an error status
      const errorData = await response.text();
      throw new Error(`HTTP error! Status: ${response.status}, Details: ${errorData}`);
    }

    const data = await response.json();
    return data;
  } catch (error) {
    // This catch block would handle 'fetch failed' errors (e.g., network issues, server unreachable)
    console.error('API request to /api/employees failed:', error);
    throw error; // Re-throw to propagate the error to the UI
  }
};
